func TestCacheData_JSONSerialization(t *testing.T) {
	// Given: Cache data
	now := time.Now()
	data := &CacheData{
		LastCheck:       now,
		CurrentVersion:  "v0.1.2",

		CurrentVersion:  "v0.1.2",
		LatestVersion:   "v0.1.3",
		UpdateAvailable: true,
